targets.expr:
sum by (service) (
    rate(
        cilium_lb_bytes_total{node=~"^${node}$", service=~"^${service}$", backend=~"^${backend}$"}[$__rate_interval]
    ) 
    * on (node) group_left() (
        kube_node_labels{label_service_cilium_io_node=~"t1"}
    )
) != 0

sum by (service) (
    rate(
        cilium_lb_packets_total{node=~"^${node}$", service=~"^${service}$", backend=~"^${backend}$"}[$__rate_interval]
    ) 
    * on (node) group_left() (
        kube_node_labels{label_service_cilium_io_node=~"t1"}
    )
) != 0

sum by (backend) (
    rate(
        cilium_lb_bytes_total{node=~"^${node}$", service=~"^${service}$", backend=~"^${backend}$"}[$__rate_interval]
    ) 
    * on (node) group_left() (
        kube_node_labels{label_service_cilium_io_node=~"t1"}
    )
) != 0

sum by (backend) (
    rate(
        cilium_lb_packets_total{node=~"^${node}$", service=~"^${service}$", backend=~"^${backend}$"}[$__rate_interval]
    ) 
    * on (node) group_left() (
        kube_node_labels{label_service_cilium_io_node=~"t1"}
    )
) != 0

sum by (instance) (
    rate(
        {__name__=~"node_ethtool_received_queue_.*_xdp_bytes"}[$__rate_interval])
    ) * on (instance) group_left(node) (
        label_replace(kube_node_status_addresses{node=~"${node}"}, "instance", "$1:9100", "address", "(.*)"
    )
) * on (node) (
    kube_node_labels{label_service_cilium_io_node="t1"}
) != 0

sum by (instance) (
    rate(
        {__name__=~"node_ethtool_received_queue_.*_xdp_packets"}[$__rate_interval])
    ) * on (instance) group_left(node) (
        label_replace(kube_node_status_addresses{node=~"${node}"}, "instance", "$1:9100", "address", "(.*)"
    )
) * on (node) (
    kube_node_labels{label_service_cilium_io_node="t1"}
) != 0
